    },
    {
        "structure": "1.3.1.1",
        "title": "1、重角色路径：以 《鸣潮》《原神》为代表，将角色作为核心互动触点，深耕角色 IP，借版本更新、角色纪念日策划 UGC 活动，深化用户情感绑定。",
        "physical_index": "<physical_index_96>"
    },
    {
        "structure": "1.3.1.2",
        "title": "2、重故事路径：以 《燕云十六声》为代表，绑定文化与剧情核心资产，通过海外社媒解析游戏历史文化背景，推动用户成为世界观共建者。",
        "physical_index": "<physical_index_96>"
    },
    {
        "structure": "1.3.2",
        "title": "二、和社区玩在一起：竞技类游戏的 “玩家共创式” 品牌运营新范式",
        "physical_index": "<physical_index_96>"
    },
    {
        "structure": "1.3.2.1",
        "title": "1、搭建双向沟通桥梁：在社媒搭建玩家共创阵地，收集优化反馈，邀请核心玩家参与共创，同步建议落地成效，推动玩家转为品牌共建者。",
        "physical_index": "<physical_index_96>"
    },
    {
        "structure": "1.3.2.2",
        "title": "2、打通社区与赛事生态联动：联动社媒发起玩法创作赛事，将优质 UGC 纳入官方矩阵与赛事，吸纳高玩参与二创传播，强化玩家认同与社群粘性。",
        "physical_index": "<physical_index_96>"
    }
]

